import type { SupabaseClient } from "@supabase/supabase-js";
import type { ArticleStats } from "../types";

/**
 * Get view count for a specific article.
 */
export async function getArticleViews(
  supabase: SupabaseClient,
  articleId: string,
) {
  const { count, error } = await supabase
    .from("article_analytics")
    .select("id", { count: "exact", head: true })
    .eq("article_id", articleId);

  if (error) throw error;
  return count ?? 0;
}

/**
 * Get popular articles by view count within a date range.
 */
export async function getPopularArticles(
  supabase: SupabaseClient,
  options: { days?: number; limit?: number } = {},
) {
  const { days = 30, limit = 10 } = options;

  const since = new Date();
  since.setDate(since.getDate() - days);

  const { data, error } = await supabase.rpc("get_popular_articles", {
    since_date: since.toISOString(),
    result_limit: limit,
  });

  if (error) {
    // Fallback: manual query if RPC not available
    const { data: views } = await supabase
      .from("article_analytics")
      .select("article_id")
      .gte("viewed_at", since.toISOString());

    const countMap = new Map<string, number>();
    views?.forEach((v) => {
      countMap.set(v.article_id, (countMap.get(v.article_id) ?? 0) + 1);
    });

    const sorted = Array.from(countMap.entries())
      .sort((a, b) => b[1] - a[1])
      .slice(0, limit);

    if (sorted.length === 0) return [];

    const { data: articles } = await supabase
      .from("articles")
      .select("id, title, slug")
      .in(
        "id",
        sorted.map(([id]) => id),
      );

    return sorted.map(([articleId, total_views]) => {
      const article = articles?.find((a) => a.id === articleId);
      return {
        article_id: articleId,
        title: article?.title ?? "",
        slug: article?.slug ?? "",
        total_views,
        views_today: 0,
        views_this_week: 0,
        views_this_month: total_views,
      } satisfies ArticleStats;
    });
  }

  return (data ?? []) as ArticleStats[];
}

/**
 * Get total views across all articles for a date range.
 */
export async function getTotalViews(
  supabase: SupabaseClient,
  days = 30,
) {
  const since = new Date();
  since.setDate(since.getDate() - days);

  const { count, error } = await supabase
    .from("article_analytics")
    .select("id", { count: "exact", head: true })
    .gte("viewed_at", since.toISOString());

  if (error) throw error;
  return count ?? 0;
}
