import type { SupabaseClient } from "@supabase/supabase-js";
import type { Category } from "../types";

/**
 * Fetch all categories ordered by sort_order.
 */
export async function getCategories(supabase: SupabaseClient) {
  const { data, error } = await supabase
    .from("categories")
    .select("*")
    .order("sort_order", { ascending: true });

  if (error) throw error;
  return (data as Category[]) ?? [];
}

/**
 * Fetch a single category by slug.
 */
export async function getCategoryBySlug(
  supabase: SupabaseClient,
  slug: string,
) {
  const { data, error } = await supabase
    .from("categories")
    .select("*")
    .eq("slug", slug)
    .single();

  if (error) throw error;
  return data as Category | null;
}

/**
 * Fetch categories with article counts.
 */
export async function getCategoriesWithCounts(supabase: SupabaseClient) {
  const { data: categories, error } = await supabase
    .from("categories")
    .select("*")
    .order("sort_order", { ascending: true });

  if (error) throw error;

  // Get counts per category
  const { data: counts } = await supabase
    .from("articles")
    .select("category_id")
    .eq("status", "published");

  const countMap = new Map<string, number>();
  counts?.forEach((a) => {
    if (a.category_id) {
      countMap.set(a.category_id, (countMap.get(a.category_id) ?? 0) + 1);
    }
  });

  return (categories ?? []).map((cat) => ({
    ...(cat as Category),
    article_count: countMap.get(cat.id) ?? 0,
  }));
}
