import type { SupabaseClient } from "@supabase/supabase-js";
import type { Article, ArticleFilters, Tag } from "../types";

/**
 * Fetch articles with optional filtering, pagination, and sorting.
 */
export async function getArticles(
  supabase: SupabaseClient,
  filters: ArticleFilters = {},
) {
  const {
    status,
    category_id,
    tag_id,
    search,
    author_id,
    limit = 20,
    offset = 0,
    orderBy = "published_at",
    orderDirection = "desc",
  } = filters;

  let query = supabase
    .from("articles")
    .select("*, category:categories(*)", { count: "exact" });

  // Status filter
  if (status) {
    if (Array.isArray(status)) {
      query = query.in("status", status);
    } else {
      query = query.eq("status", status);
    }
  }

  if (category_id) {
    query = query.eq("category_id", category_id);
  }

  if (author_id) {
    query = query.eq("author_id", author_id);
  }

  if (search) {
    query = query.or(
      `title.ilike.%${search}%,excerpt.ilike.%${search}%,content_html.ilike.%${search}%`,
    );
  }

  query = query
    .order(orderBy, { ascending: orderDirection === "asc", nullsFirst: false })
    .range(offset, offset + limit - 1);

  const { data, error, count } = await query;

  if (error) throw error;

  // If filtering by tag, we need a separate query
  let articles = (data as Article[]) ?? [];

  if (tag_id && articles.length > 0) {
    const { data: taggedIds } = await supabase
      .from("article_tags")
      .select("article_id")
      .eq("tag_id", tag_id);

    const taggedArticleIds = new Set(
      taggedIds?.map((t) => t.article_id) ?? [],
    );
    articles = articles.filter((a) => taggedArticleIds.has(a.id));
  }

  return { articles, total: count ?? 0 };
}

/**
 * Fetch a single article by slug. Includes category and tags.
 */
export async function getArticleBySlug(
  supabase: SupabaseClient,
  slug: string,
  includeDrafts = false,
) {
  let query = supabase
    .from("articles")
    .select("*, category:categories(*)")
    .eq("slug", slug);

  if (!includeDrafts) {
    query = query.eq("status", "published");
  }

  const { data: article, error } = await query.single();

  if (error) throw error;
  if (!article) return null;

  // Fetch tags for this article
  const { data: tagRelations } = await supabase
    .from("article_tags")
    .select("tag_id, tags(*)")
    .eq("article_id", article.id);

  const tags =
    (tagRelations
      ?.map((r) => r.tags)
      .flat()
      .filter(Boolean) as unknown as Tag[]) ?? [];

  return { ...(article as unknown as Article), tags };
}

/**
 * Fetch a single article by ID (for admin editing).
 */
export async function getArticleById(
  supabase: SupabaseClient,
  id: string,
) {
  const { data: article, error } = await supabase
    .from("articles")
    .select("*, category:categories(*)")
    .eq("id", id)
    .single();

  if (error) throw error;
  if (!article) return null;

  // Fetch tags
  const { data: tagRelations } = await supabase
    .from("article_tags")
    .select("tag_id, tags(*)")
    .eq("article_id", article.id);

  const tags =
    (tagRelations
      ?.map((r) => r.tags)
      .flat()
      .filter(Boolean) as unknown as Tag[]) ?? [];

  return { ...(article as unknown as Article), tags };
}

/**
 * Fetch published articles count.
 */
export async function getArticleCount(
  supabase: SupabaseClient,
  status?: string,
) {
  let query = supabase
    .from("articles")
    .select("id", { count: "exact", head: true });

  if (status) {
    query = query.eq("status", status);
  }

  const { count, error } = await query;
  if (error) throw error;

  return count ?? 0;
}
