import type { SupabaseClient } from "@supabase/supabase-js";
import type { Tag } from "../types";

/**
 * Fetch all tags ordered by name.
 */
export async function getTags(supabase: SupabaseClient) {
  const { data, error } = await supabase
    .from("tags")
    .select("*")
    .order("name", { ascending: true });

  if (error) throw error;
  return (data as Tag[]) ?? [];
}

/**
 * Fetch popular tags based on article count.
 */
export async function getPopularTags(
  supabase: SupabaseClient,
  limit = 20,
) {
  const { data: tagRelations, error } = await supabase
    .from("article_tags")
    .select("tag_id, tags(*)");

  if (error) throw error;

  // Count articles per tag
  const tagCounts = new Map<string, { tag: Tag; count: number }>();
  tagRelations?.forEach((rel) => {
    if (rel.tags) {
      const tag = rel.tags as unknown as Tag;
      const existing = tagCounts.get(tag.id);
      if (existing) {
        existing.count++;
      } else {
        tagCounts.set(tag.id, { tag, count: 1 });
      }
    }
  });

  return Array.from(tagCounts.values())
    .sort((a, b) => b.count - a.count)
    .slice(0, limit)
    .map(({ tag, count }) => ({ ...tag, article_count: count }));
}

/**
 * Fetch tags for a specific article.
 */
export async function getTagsForArticle(
  supabase: SupabaseClient,
  articleId: string,
) {
  const { data, error } = await supabase
    .from("article_tags")
    .select("tags(*)")
    .eq("article_id", articleId);

  if (error) throw error;
  return (
    (data
      ?.map((r) => r.tags)
      .flat()
      .filter(Boolean) as unknown as Tag[]) ?? []
  );
}
